using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tarefa #31 — ponto de entrada nomeado dentro da cena de uma área (ver
/// AreaData.sceneName/spawnPointIds). Colocar em portas/entradas/checkpoints
/// da cena; ao concluir uma transição (AreaTransition → AreaManager →
/// SceneLoader), o AreaManager procura o AreaSpawnPoint cujo "spawnId"
/// corresponda a AreaTransition.targetSpawnPointId e reposiciona o player
/// na posição deste objecto.
///
/// IDs são strings livres — basta corresponderem entre
/// AreaTransition.targetSpawnPointId e o AreaSpawnPoint da cena de destino.
/// Sugestões de convenção: "EntradaOeste", "EntradaLeste",
/// "CheckpointPrincipal".
/// </summary>
public class AreaSpawnPoint : MonoBehaviour
{
    /// <summary>
    /// Lista estática de todos os AreaSpawnPoints activos na cena — evita
    /// FindObjectsOfType em PlayerDeathHandler.ResolveCheckpointPosition.
    /// </summary>
    public static readonly List<AreaSpawnPoint> All = new List<AreaSpawnPoint>();

    [Tooltip("Identificador único desta entrada dentro da cena (ex: \"EntradaOeste\"). Deve corresponder a AreaTransition.targetSpawnPointId e, idealmente, estar listado em AreaData.spawnPointIds.")]
    public string spawnId;

    private void OnEnable()  => All.Add(this);
    private void OnDisable() => All.Remove(this);

#if UNITY_EDITOR
    private void OnDrawGizmos()
    {
        Gizmos.color = Color.cyan;
        Gizmos.DrawWireSphere(transform.position, 0.4f);
        Gizmos.DrawLine(transform.position + Vector3.left * 0.4f, transform.position + Vector3.right * 0.4f);
        Gizmos.DrawLine(transform.position + Vector3.down * 0.4f, transform.position + Vector3.up * 0.4f);
    }
#endif
}
